import { useEffect, useState } from "react";
import socket from "../socket";
import confetti from "canvas-confetti";

function Player() {
  const [name, setName] = useState("");
  const [gamePin, setGamePin] = useState("");
  const [joined, setJoined] = useState(false);

  const [question, setQuestion] = useState(null);
  const [leaderboard, setLeaderboard] = useState([]);

  const [answered, setAnswered] = useState(false);
  const [answerResult, setAnswerResult] = useState(null);
  const [gameOver, setGameOver] = useState(false);

  const [questionNumber, setQuestionNumber] = useState(0);
  const [totalQuestions, setTotalQuestions] = useState(0);
  const [timeLeft, setTimeLeft] = useState(25);

  useEffect(() => {
    socket.on("nextQuestion", (data) => {
      setQuestion(data.question);
      setQuestionNumber(data.questionNumber || 0);
      setTotalQuestions(data.totalQuestions || 0);
      setTimeLeft(data.timeLimit || 25);

      setAnswered(false);
      setAnswerResult(null);
      setGameOver(false);
    });

    socket.on("gameStarted", (data) => {
      setQuestion(data.question);
      setTimeLeft(data.timeLimit || 25);

      setAnswered(false);
      setAnswerResult(null);
      setGameOver(false);
    });

    socket.on("answerResult", (data) => {
      setAnswerResult(data);
      setAnswered(true);
    });

    socket.on("leaderboardUpdated", (data) => {
      setLeaderboard(data || []);
    });

    socket.on("leaderboard", (data) => {
      setLeaderboard(data || []);
    });

    socket.on("gameOver", (data) => {
      setLeaderboard(data || []);
      setGameOver(true);

      confetti({
        particleCount: 200,
        spread: 100,
      });
    });

    socket.on("errorMessage", (msg) => {
      alert(msg);
      setJoined(false);
    });

    return () => {
      socket.off("nextQuestion");
      socket.off("gameStarted");
      socket.off("answerResult");
      socket.off("leaderboardUpdated");
      socket.off("leaderboard");
      socket.off("gameOver");
      socket.off("errorMessage");
    };
  }, []);

  useEffect(() => {
    if (!joined || !question || answered || gameOver) return;

    if (timeLeft <= 0) {
      setAnswered(true);
      setAnswerResult({
        correct: false,
        score: null,
      });
      return;
    }

    const timer = setTimeout(() => {
      setTimeLeft((prev) => prev - 1);
    }, 1000);

    return () => clearTimeout(timer);
  }, [joined, question, answered, gameOver, timeLeft]);

  const joinGame = () => {
    if (!gamePin || !name) {
      alert("Enter Game PIN and Name");
      return;
    }

    socket.emit("joinGame", {
      gamePin,
      name,
      playerName: name,
    });

    setJoined(true);
  };

  const answer = (opt) => {
    if (answered || !question) return;

    socket.emit("answer", {
      gamePin,
      name,
      correct: opt === question.answer,
    });

    setAnswered(true);
  };

  if (!joined) {
    return (
      <div style={styles.center}>
        <h1>Join Game</h1>

        <input
          placeholder="Enter Game PIN"
          value={gamePin}
          onChange={(e) => setGamePin(e.target.value)}
          style={styles.input}
        />

        <br />

        <input
          placeholder="Enter Name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          style={styles.input}
        />

        <br />

        <button onClick={joinGame} style={styles.joinBtn}>
          Join
        </button>
      </div>
    );
  }

  if (gameOver) {
    const top3 = (leaderboard || []).slice(0, 3);

    return (
      <div style={styles.center}>
        <h1>🏆 Final Leaderboard</h1>

        {top3.length === 0 ? (
          <p>No scores yet</p>
        ) : (
          top3.map((p, i) => (
            <h2 key={i}>
              {i === 0 && "🥇"}
              {i === 1 && "🥈"}
              {i === 2 && "🥉"} {p.name} - {p.score}
            </h2>
          ))
        )}
      </div>
    );
  }

  if (answered) {
    return (
      <div style={styles.center}>
        <h1>
          {answerResult?.correct ? "✅ Correct Answer" : "❌ Answer Submitted"}
        </h1>

        {answerResult?.score !== null && answerResult?.score !== undefined && (
          <h2>Your Score: {answerResult.score}</h2>
        )}

        <p>Waiting for other players...</p>

        <h2>Live Leaderboard</h2>

        {(leaderboard || []).length === 0 ? (
          <p>Leaderboard will update soon</p>
        ) : (
          (leaderboard || []).map((p, i) => (
            <p key={i}>
              #{i + 1} {p.name} - {p.score}
            </p>
          ))
        )}
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <h2>
        Question {questionNumber}/{totalQuestions}
      </h2>

      <h3>Time Left: {timeLeft}s</h3>

      <h1>{question ? question.question : "Waiting for host to start..."}</h1>

      {(question?.options || []).map((opt, i) => (
        <button key={i} onClick={() => answer(opt)} style={styles.btn}>
          {opt}
        </button>
      ))}
    </div>
  );
}

export default Player;

const styles = {
  container: {
    padding: 20,
    textAlign: "center",
  },
  center: {
    textAlign: "center",
    marginTop: 100,
  },
  input: {
    padding: 12,
    margin: 10,
    width: 250,
    fontSize: 16,
  },
  joinBtn: {
    padding: 12,
    margin: 10,
    width: 150,
    fontSize: 16,
  },
  btn: {
    display: "block",
    margin: "10px auto",
    padding: 20,
    width: "80%",
    fontSize: 18,
  },
};
